urlset:
{%- for entry in entries %}

        {{ entry.permalink | escape_xml | safe }}
        {%- if entry.updated %}
        {{ entry.updated }}
        {%- endif %}
        {%- if entry.extra.preview_image %}
        {%- set img = entry.extra.preview_image | trim_start_matches(pat='/') -%}

            {%- if img is starting_with("http") %}
            {{ img | escape_xml | safe }}
            {%- else %}
            https://organicmaps.app/{{ img | escape_xml | safe }}
            {%- endif %}

        {%- endif %}

{%- endfor %}
